import{c as e,Q as s,j as n,m as o}from"./chunks/framework.iD28w_5a.js";const h=JSON.parse('{"title":"GUI Canvas 排查","description":"","frontmatter":{"title":"GUI Canvas 排查"},"headers":[],"relativePath":"notes/029/1.md","filePath":"notes/029/1.md","lastUpdated":1779686691000}'),t={name:"notes/029/1.md"};function i(r,a,l,d,c,p){return s(),n("div",null,[...a[0]||(a[0]=[o(`<h1 id="_029-gui-canvas-排查笔记" tabindex="-1">029_gui_canvas 排查笔记 <a class="header-anchor" href="#_029-gui-canvas-排查笔记" aria-label="Permalink to &quot;029_gui_canvas 排查笔记&quot;">​</a></h1><h2 id="问题-1-canvas-测试后内核-hang-test-fifo-ordering" tabindex="-1">问题 1：Canvas 测试后内核 hang（test_fifo_ordering） <a class="header-anchor" href="#问题-1-canvas-测试后内核-hang-test-fifo-ordering" aria-label="Permalink to &quot;问题 1：Canvas 测试后内核 hang（test_fifo_ordering）&quot;">​</a></h2><h3 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h3><p>GUI ON 时，Canvas 测试全部通过后，<code>test_fifo_ordering</code> 在创建 <code>fifo_owner</code> 后 hang。GUI OFF 时基线 356 测试全过。</p><h3 id="根因" tabindex="-1">根因 <a class="header-anchor" href="#根因" aria-label="Permalink to &quot;根因&quot;">​</a></h3><p>Heap expand 无上限检查。<code>KMEM_HEAP_SIZE = 1MB</code>（仅初始大小），Heap 可无限 expand。Canvas 每次 <code>init()</code> 分配 ~3MB back_buf（1024x768x4），Heap 扩展到 ~3MB 后越界进入 MMIO/Stack 虚拟地址区域，导致 VMM 页表映射冲突，后续 TaskBuilder 分配栈时 <code>g_vmm.map()</code> 行为异常。</p><h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h3><ul><li><code>heap.hpp</code>：新增 <code>max_size_</code> 字段</li><li><code>heap.cpp</code>：<code>init()</code> 中设置 <code>max_size_ = KMEM_HEAP_SIZE</code>；<code>expand()</code> 中检查 <code>size_ + expand_size &gt; max_size_</code> 则返回 false</li><li><code>memory_layout.hpp</code>：<code>KMEM_HEAP_SIZE</code> 从 1MB 提到 128MB（GUI OS 合理值，物理页按需分配不浪费）</li></ul><h2 id="问题-2-test-create-user-space-hang" tabindex="-1">问题 2：test_create_user_space hang <a class="header-anchor" href="#问题-2-test-create-user-space-hang" aria-label="Permalink to &quot;问题 2：test_create_user_space hang&quot;">​</a></h2><h3 id="现象-1" tabindex="-1">现象 <a class="header-anchor" href="#现象-1" aria-label="Permalink to &quot;现象&quot;">​</a></h3><p>Heap 修复后，GUI ON 时 <code>test_create_user_space</code> hang。AddressSpace 构造中 <code>phys_to_virt(pml4_phys_)</code> = <code>phys + 0xFFFFFFFF80000000</code>，当 PMM 分配的物理页超过 loader 映射范围时 page fault。</p><h3 id="根因-1" tabindex="-1">根因 <a class="header-anchor" href="#根因-1" aria-label="Permalink to &quot;根因&quot;">​</a></h3><p>Loader 的 <code>identity_map_up_to()</code> 只映射到 ELF 段末尾（~20MB）。PMM 管理 9GB 物理内存，<code>alloc_page()</code> 可返回任意地址。当返回 &gt;20MB 的物理页时，<code>phys_to_virt()</code> 返回的虚拟地址未被映射，访问即 page fault。</p><p>Canvas 测试消耗了大量低地址物理页（Heap expand），使后续分配更容易落到高地址区域。</p><h3 id="修复-1" tabindex="-1">修复 <a class="header-anchor" href="#修复-1" aria-label="Permalink to &quot;修复&quot;">​</a></h3><ul><li><code>big_kernel_loader.cpp</code>：phase2 中扫描 BootInfo 的 E820 memory map，找最高可用 RAM 地址，映射全部物理内存（Linux-style full direct map）</li><li>用 2MB 大页映射 0-1GB，1GB 大页映射 &gt;=1GB，开销极小（8GB 仅需 ~5 页页表）</li></ul><h3 id="附带修复" tabindex="-1">附带修复 <a class="header-anchor" href="#附带修复" aria-label="Permalink to &quot;附带修复&quot;">​</a></h3><ul><li><code>test_vmm.cpp</code>：<code>test_demand_page</code> 原来依赖地址未映射来触发 page fault，全量 direct map 后该假设不成立。改为验证高地址可通过 direct map 正常读写。</li></ul><h2 id="虚拟内存布局-修复后" tabindex="-1">虚拟内存布局（修复后） <a class="header-anchor" href="#虚拟内存布局-修复后" aria-label="Permalink to &quot;虚拟内存布局（修复后）&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0xFFFF8000_00000000  KMEM_HEAP_BASE     (128 MB reserved)</span></span>
<span class="line"><span>0xFFFF8000_08000000  KMEM_MMIO_BASE     (256 KB)</span></span>
<span class="line"><span>0xFFFF8000_08040000  KMEM_STACK_BASE    (1 MB, 向上增长)</span></span>
<span class="line"><span>0xFFFF8000_08140000  KMEM_DMA_BASE      (1 MB)</span></span>
<span class="line"><span>0xFFFF8000_08240000  KMEM_EXT2_DMA_BASE (1 MB)</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>0xFFFF_FFFF_80000000  KERNEL_VMA (direct physical map, 全量)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="教训" tabindex="-1">教训 <a class="header-anchor" href="#教训" aria-label="Permalink to &quot;教训&quot;">​</a></h2><ol><li><strong>Heap expand 必须有上限</strong>：不能假设&quot;虚拟地址空间无限就随便扩展&quot;，必须检查预留区域边界</li><li><strong>phys_to_virt 依赖 direct map 覆盖</strong>：loader 只映射 ELF 段是不够的，PMM 可能返回任意物理地址，必须全量映射或实现 kmap</li><li><strong>测试要覆盖资源消耗场景</strong>：大块分配（Canvas 3MB）在单元测试中不可见，只有内核集成测试才会暴露内存布局冲突</li></ol>`,22)])])}const u=e(t,[["render",i]]);export{h as __pageData,u as default};
